  ('locality-6f0ba476-moex-00229', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲將其對乙之債權讓與於丙時，應具備下列何者要件，始得對乙發生效力？', '["甲、乙、丙三人之書面合意", "甲、乙、丙三人之口頭合意", "甲、丙達成合意，並應由甲與丙共同通知乙", "甲、丙達成合意，並應由甲或丙通知乙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00230', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於代理權消滅之敘述，何者正確？', '["代理人不得拋棄其代理權", "代理人死亡，代理權得為繼承之標的", "代理人喪失行為能力時，代理權消滅", "受僱人被解僱時，其代理權仍不消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00231', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '當事人間無特別約定時，下列何種情形得互相主張同時履行抗辯權？', '["委任人償還費用之義務與受任人處理委任事務之義務", "清償人之給付與受領清償人之受領證書之給與", "承攬人交付完成物之義務與定作人給付報酬之義務", "承攬人返還定作物剩餘材料之義務與定作人給付報酬之義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00232', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲建設公司與乙營造廠訂立承攬契約，委託乙興建大樓；乙之受僱人丙於搭鷹架時，因過失掉落 榔頭，致路人丁受傷。下列敘述何者正確？', '["甲無須為丙之行為，對丁負損害賠償責任", "乙無須為丙之行為，對丁負損害賠償責任", "甲與乙均無須為丙之行為負損害賠償責任", "甲與乙對丙之行為應連帶負損害賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00233', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲將其所有土地出租於乙種植作物，約定由甲於每年 6 月 30 日赴乙處受領所收成作物之一定數 量作為租金。乙於締約第2年之6月28日備妥約定給付之作物後，甲並未於約定期日赴乙處受 領。乙礙於該批作物數量不貲且易腐壞，乃於7月2日僱用車輛載運該批作物赴甲處欲為給付， 卻遭甲拒絕受領，乙乃將同批貨物出售並提存價款於法院。下列敘述何者錯誤？', '["乙得請求甲給付僱用車輛載運該批作物之費用", "乙未直接給付出售作物之價金於甲，不生清償效力", "乙已提出給付，之後對該提出給付之保管，僅於其有故意或重大過失時，始負責任", "甲未赴乙處收租，構成受領遲延，不得以乙欠租終止租約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00234', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲為追求乙，允諾將名下之A屋贈與乙，但未經公證。下列敘述何者錯誤？', '["甲將A屋之所有權移轉登記於乙前，甲得隨時撤銷贈與契約，乙不得請求甲辦理移轉登記", "甲將A屋之所有權移轉登記於乙，乙入住後發現A屋之窗戶有瑕疵，每逢下雨天必滲水。若甲 事前不知該瑕疵之存在，亦未保證A屋無瑕疵，乙不得請求甲負責修繕", "甲將 A 屋之所有權移轉登記於乙前，與乙大吵一架，憤而燒毀 A 屋。但因贈與契約為無償契 約，且該契約未經公證，故甲無須對乙負損害賠償責任", "甲之配偶丙得知甲將A屋贈與乙後，心有不甘而辱罵乙。乙不甘受辱，故意開車撞傷丙。甲得 於知悉該情事1年內，撤銷贈與契約 31670 32070"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
